public class Solution {
  public List<Integer> countPrimeNumbers(int n) {
    List<Integer> primes = new ArrayList<>();
    for (int i = 2; i < n; i++) {
      boolean isPrime = true; 
      for (int j = 2; j * j <= i; j++) {
        if (i % j == 0) {
          isPrime = false;
          break;  // break inner loop as soon as a divisor is found
        }
      }
      if (isPrime) {
        primes.add(i);  // only add prime numbers to the list
      }
    }
    return primes;
  }

